  { metro_name: 'Laramie, WY', state: 'WY', latitude: 41.3114, longitude: -105.5911, radius_meters: 15000, population: 32158, priority: 0 },
  { metro_name: 'Gillette, WY', state: 'WY', latitude: 44.2911, longitude: -105.5022, radius_meters: 15000, population: 33403, priority: 0 },
  { metro_name: 'Pocatello, ID', state: 'ID', latitude: 42.8713, longitude: -112.4455, radius_meters: 20000, population: 56264, priority: 1 },
  { metro_name: 'Twin Falls, ID', state: 'ID', latitude: 42.5558, longitude: -114.4701, radius_meters: 20000, population: 51807, priority: 1 },
  { metro_name: 'Elko, NV', state: 'NV', latitude: 40.8324, longitude: -115.7631, radius_meters: 15000, population: 20279, priority: 0 },
  { metro_name: 'Cedar City, UT', state: 'UT', latitude: 37.6775, longitude: -113.0619, radius_meters: 15000, population: 35464, priority: 0 }
];

const config = $input.first().json;
return metros.map(m => ({
  json: { ...m, country: 'US', supabase_url: config.supabase_url, supabase_key: config.supabase_key }
}));

// Upsert each metro into pipeline_queue
const item = $input.item.json;
const url = item.supabase_url;
const key = item.supabase_key;

const row = {
  metro_name: item.metro_name,
  state: item.state,
  country: item.country,
  latitude: item.latitude,
  longitude: item.longitude,
  radius_meters: item.radius_meters,
  population: item.population,
  priority: item.priority
};

try {
  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: url + '/rest/v1/pipeline_queue',
    headers: {
      apikey: key,
      Authorization: 'Bearer ' + key,
      'Content-Type': 'application/json',
      Prefer: 'resolution=merge-duplicates,return=representation'
    },
    body: row,
    json: true
  });
  return { json: { metro_name: item.metro_name, status: 'upserted', id: result?.[0]?.id } };
} catch (err) {
  return { json: { metro_name: item.metro_name, status: 'error', message: err.message } };
}
